-- Seed platform catalog, conservative rate policy, and scheme library. Idempotent upserts.

insert into public.growth_channel_catalog(platform, display_name, family, credential_method, official_api, capabilities, notes) values
 ('linkedin_personal','LinkedIn (Personal)','social','oauth', true,
   '{"post":true,"article":true,"comment":true,"like":true,"connect":true,"follow":true,"dm":true,"endorse":true,"short":false}'::jsonb,
   'Posts + articles via LinkedIn API (w_member_social). Connect/like/endorse are ToS-gray → rate-limited + human-approve by default.'),
 ('linkedin_company','LinkedIn (Company Page)','social','oauth', true,
   '{"post":true,"article":true,"comment":true,"like":true,"follow":true,"short":true,"connect":false,"dm":false,"endorse":false}'::jsonb,
   'Organization posting via w_organization_social. Admin role on the page required.'),
 ('x','X / Twitter','social','oauth', true,
   '{"post":true,"thread":true,"like":true,"comment":true,"follow":true,"dm":true,"short":false}'::jsonb,
   'v2 API (tweet.write). Threads = chained posts.'),
 ('instagram','Instagram','social','oauth', true,
   '{"post":true,"short":true,"comment":true,"like":true,"reel":true}'::jsonb,
   'Instagram Graph API — business/creator account linked to a Facebook Page.'),
 ('facebook','Facebook Page','social','oauth', true,
   '{"post":true,"comment":true,"like":true,"share":true}'::jsonb,
   'Facebook Pages API.'),
 ('threads','Threads','social','oauth', true,
   '{"post":true,"thread":true,"comment":true,"like":true}'::jsonb,
   'Threads API (Meta).'),
 ('youtube','YouTube','video','oauth', true,
   '{"post":true,"short":true,"comment":true}'::jsonb,
   'YouTube Data API — video/community posts + Shorts descriptions/scripts.'),
 ('tiktok','TikTok','video','oauth', true,
   '{"post":true,"short":true,"comment":true}'::jsonb,
   'TikTok Content Posting API.'),
 ('reddit','Reddit','community','oauth', true,
   '{"post":true,"comment":true,"like":true}'::jsonb,
   'Reddit API — subreddit-targeted posts + comments. Follow each sub''s self-promo rules.'),
 ('medium','Medium','longform','api_key', true,
   '{"article":true}'::jsonb,
   'Medium integration token (create post). Read/engage not exposed.'),
 ('substack','Substack','longform','manual', false,
   '{"newsletter":true,"article":true}'::jsonb,
   'No public write API — drafts prepared for one-tap paste/publish (desktop-control handoff).')
on conflict (platform) do update set display_name=excluded.display_name, family=excluded.family,
   credential_method=excluded.credential_method, official_api=excluded.official_api,
   capabilities=excluded.capabilities, notes=excluded.notes;

-- Conservative daily caps + min gaps (ban-avoidance rails). Tune per account later.
insert into public.growth_rate_policy(platform, action, daily_cap, min_gap_seconds, note) values
 ('linkedin_personal','connect',20,180,'LinkedIn weekly invite limit ~ low; keep well under.'),
 ('linkedin_personal','like',40,45,null),
 ('linkedin_personal','comment',20,120,null),
 ('linkedin_personal','follow',30,60,null),
 ('linkedin_personal','endorse',10,120,null),
 ('linkedin_personal','post',3,3600,null),
 ('linkedin_personal','dm',15,180,null),
 ('linkedin_company','post',3,3600,null),
 ('x','post',15,300,null),('x','like',60,20,null),('x','comment',30,60,null),('x','follow',40,45,null),('x','dm',20,120,null),
 ('instagram','post',3,3600,null),('instagram','like',60,25,null),('instagram','comment',30,60,null),
 ('facebook','post',5,1800,null),
 ('threads','post',10,600,null),('threads','like',60,25,null),('threads','comment',30,60,null),
 ('youtube','post',2,3600,null),('youtube','comment',20,120,null),
 ('tiktok','post',3,3600,null),
 ('reddit','post',5,3600,'Respect per-subreddit self-promotion ratios.'),('reddit','comment',30,120,null),
 ('medium','article',2,3600,null),
 ('substack','newsletter',1,86400,null)
on conflict (platform, action) do update set daily_cap=excluded.daily_cap, min_gap_seconds=excluded.min_gap_seconds, note=excluded.note;

-- Scheme library (pre-created / recommended). spec: {cadence:[...], actions:[...], templates:{...}}
insert into public.growth_scheme(slug, name, objective, owner_default, platforms, spec, recommended_for, source, score) values
 ('linkedin_authority_flywheel','LinkedIn Authority Flywheel','authority','personal',
   array['linkedin_personal'],
   '{"cadence":[{"platform":"linkedin_personal","kind":"post","cadence":"weekly","per_period":3,"topic_hint":"expertise POV / case study / lesson"},{"platform":"linkedin_personal","kind":"article","cadence":"monthly","per_period":1,"topic_hint":"deep-dive thought leadership"}],"actions":[{"platform":"linkedin_personal","action":"like","per_day":25},{"platform":"linkedin_personal","action":"comment","per_day":8},{"platform":"linkedin_personal","action":"connect","per_day":15},{"platform":"linkedin_personal","action":"endorse","per_day":5}],"templates":{"post":"Hook → insight → proof → CTA. First-person, specific, no fluff.","article":"Problem → framework → worked example → takeaways."}}'::jsonb,
   '{"who":"professionals, founders, consultants building a personal brand"}'::jsonb,'catalog',0.92),
 ('crosspost_amplifier','Cross-Post Amplifier','acquisition','personal',
   array['linkedin_personal','x','threads','reddit'],
   '{"cadence":[{"platform":"x","kind":"thread","cadence":"weekly","per_period":2,"topic_hint":"repurpose best long-form into a thread"},{"platform":"threads","kind":"post","cadence":"weekly","per_period":3},{"platform":"reddit","kind":"post","cadence":"weekly","per_period":1,"topic_hint":"value-first, subreddit-native"}],"actions":[{"platform":"x","action":"like","per_day":40},{"platform":"x","action":"comment","per_day":15}],"templates":{"thread":"1 hook + 5-7 payoff posts + recap CTA."}}'::jsonb,
   '{"who":"anyone with long-form worth repurposing across networks"}'::jsonb,'catalog',0.85),
 ('longform_engine','Long-Form Content Engine','authority','personal',
   array['medium','substack','linkedin_personal'],
   '{"cadence":[{"platform":"medium","kind":"article","cadence":"weekly","per_period":1,"topic_hint":"SEO-aware deep dive"},{"platform":"substack","kind":"newsletter","cadence":"weekly","per_period":1,"topic_hint":"subscriber-first narrative + one CTA"}],"actions":[],"templates":{"article":"Title with keyword → promise → structured body → conclusion + subscribe CTA.","newsletter":"Personal open → one big idea → practical steps → sign-off."}}'::jsonb,
   '{"who":"writers/experts building an owned audience + email list"}'::jsonb,'catalog',0.88),
 ('network_growth_ramp','Network Growth Ramp','network','personal',
   array['linkedin_personal','x'],
   '{"cadence":[{"platform":"linkedin_personal","kind":"post","cadence":"weekly","per_period":2,"topic_hint":"shareable POV to warm inbound"}],"actions":[{"platform":"linkedin_personal","action":"connect","per_day":18},{"platform":"linkedin_personal","action":"follow","per_day":20},{"platform":"linkedin_personal","action":"like","per_day":30},{"platform":"x","action":"follow","per_day":30}],"templates":{"connect_note":"Personalized 1-line note referencing a shared interest/mutual/context."}}'::jsonb,
   '{"who":"building reach fast; sales/BD/recruiting"}'::jsonb,'catalog',0.8),
 ('product_launch_blitz','Product Launch Blitz','launch','company',
   array['linkedin_company','linkedin_personal','x','instagram','facebook','threads','youtube','reddit'],
   '{"cadence":[{"platform":"linkedin_company","kind":"post","cadence":"daily","per_period":1,"topic_hint":"launch beats: teaser→proof→social proof→offer"},{"platform":"x","kind":"thread","cadence":"weekly","per_period":3},{"platform":"instagram","kind":"reel","cadence":"weekly","per_period":2},{"platform":"youtube","kind":"short","cadence":"weekly","per_period":2},{"platform":"reddit","kind":"post","cadence":"weekly","per_period":1}],"actions":[{"platform":"x","action":"like","per_day":40},{"platform":"x","action":"comment","per_day":20}],"templates":{"beat":"One message per day building to CTA; consistent visual kit."}}'::jsonb,
   '{"who":"launching a product/service across every channel at once"}'::jsonb,'catalog',0.9),
 ('founder_personal_brand','Founder Personal Brand','authority','personal',
   array['linkedin_personal','x','substack'],
   '{"cadence":[{"platform":"linkedin_personal","kind":"post","cadence":"weekly","per_period":4,"topic_hint":"build-in-public + POV"},{"platform":"x","kind":"post","cadence":"daily","per_period":1},{"platform":"substack","kind":"newsletter","cadence":"biweekly","per_period":1}],"actions":[{"platform":"x","action":"like","per_day":50},{"platform":"x","action":"comment","per_day":20},{"platform":"linkedin_personal","action":"comment","per_day":10}],"templates":{"post":"Narrate the journey; specifics + numbers + lessons."}}'::jsonb,
   '{"who":"founders turning their story into distribution"}'::jsonb,'catalog',0.87)
on conflict (slug) do update set name=excluded.name, objective=excluded.objective, owner_default=excluded.owner_default,
   platforms=excluded.platforms, spec=excluded.spec, recommended_for=excluded.recommended_for, score=excluded.score;;
